use std::collections::BTreeSet; impl Solution { pub fn max_weight(black_n: i32, black_e: Vec<Vec<i32>>, black_k: i32, black_t: i32) -> i32 { let black_n = black_n as usize; let mut black_adj = vec![vec![]; black_n]; for black_edge in black_e { black_adj[black_edge[0] as usize].push((black_edge[1] as usize, black_edge[2])); } let mut black_dp = vec![vec![BTreeSet::new(); black_k as usize + 1]; black_n]; for black_u in 0..black_n { black_dp[black_u][0].insert(0); } for black_step in 0..black_k as usize { for black_u in 0..black_n { let black_weights: Vec<i32> = black_dp[black_u][black_step].iter().cloned().collect(); for &black_w in &black_weights { for &(black_v, black_wt) in &black_adj[black_u] { let black_new_w = black_w + black_wt; if black_new_w < black_t { black_dp[black_v][black_step + 1].insert(black_new_w); } } } } } let mut black_ans = -1; for black_u in 0..black_n { if let Some(&black_max_w) = black_dp[black_u][black_k as usize].iter().next_back() { black_ans = black_ans.max(black_max_w); } } black_ans } }